// // This LFSR is designed to generate a pseudo-random sequence by XORing the feedback taps. However, it does not reset to 6'b000001 when the reset signal (rst) is active.
module fibonacci_lfsr_6 
(
  input rst,
  input clk,

  output reg [5:0] out
);

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      out <= 6'b000001;
    end 
	else 
	begin
      out <= {out[4:0], out[5] ^ out[3]};
    end
  end

endmodule
